// ---------------------------------------------------------------------------
// Proxy Token Helpers
// ---------------------------------------------------------------------------

/**
 * Seed a proxy_token record for acceptance tests and return the raw token.
 * The raw token is sent as `X-Brain-Auth` header; the server hashes it with
 * SHA-256 and looks up the hash in the `proxy_token` table.
 */
export async function seedProxyToken(
  surreal: Surreal,
  identityId: string,
  workspaceId: string,
): Promise<string> {
  const rawToken = `brn_test_${crypto.randomUUID()}`;
  const tokenHash = createHash("sha256").update(rawToken).digest("hex");
  const tokenId = `pt-${crypto.randomUUID()}`;
  const tokenRecord = new RecordId("proxy_token", tokenId);

  await surreal.query(`CREATE $rec CONTENT $content;`, {
    rec: tokenRecord,
    content: {
      token_hash: tokenHash,
      workspace: new RecordId("workspace", workspaceId),
      identity: new RecordId("identity", identityId),
      expires_at: new Date(Date.now() + 24 * 60 * 60 * 1000),
      revoked: false,
      created_at: new Date(),
    },
  });

  return rawToken;
}

// ---------------------------------------------------------------------------
// Proxy Request Helpers (for tool injection + interception tests)
// ---------------------------------------------------------------------------

/**
 * Send a request through the LLM proxy with proxy token auth for tool injection.
 * This is the driving port for tool injection tests (step 7.5) and
 * tool interception tests (step 8.5).
 */
export async function sendProxyRequestWithIdentity(
  baseUrl: string,
  surreal: Surreal,
  user: TestUserWithMcp,
  options: {
    messages: Array<{ role: string; content: string }>;
    tools?: Array<{ name: string; description: string; input_schema: Record<string, unknown> }>;
    model?: string;
    maxTokens?: number;
    stream?: boolean;
    apiKey?: string;
  },
): Promise<Response> {
  // Cache proxy token on user object to avoid re-creating per call
  const cached = (user as unknown as { _proxyToken?: string })._proxyToken;
  const proxyToken = cached ?? await seedProxyToken(surreal, user.identityId, user.workspaceId);
  if (!cached) {
    (user as unknown as { _proxyToken?: string })._proxyToken = proxyToken;
  }

  const body = JSON.stringify({
    model: options.model ?? "claude-haiku-4-5-20251001",
    max_tokens: options.maxTokens ?? 100,
    stream: options.stream ?? false,
    messages: options.messages,
    ...(options.tools ? { tools: options.tools } : {}),
  });

  return fetch(`${baseUrl}/proxy/llm/anthropic/v1/messages`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "anthropic-version": "2023-06-01",
      "x-api-key": options.apiKey ?? "test-api-key",
      "X-Brain-Auth": proxyToken,
    },
    body,
  });
}

