  1→/**
  2→ * Milestone 9: Tool Execution via Proxy
  3→ *
  4→ * Traces: US-UI-11 (Tool Execution via Proxy)
  5→ *
  6→ * Tests the proxy pipeline's ability to execute integration-classified
  7→ * tool calls on upstream MCP servers. Uses MSW to mock the Anthropic API
  8→ * and a mock McpClientFactory for upstream MCP servers.
  9→ *
 10→ * Scenarios (7):
 11→ *   1. Single tool execution and result return
 12→ *   2. Multi-turn tool use loop (list -> comment -> text)
 13→ *   3. Max iterations safety limit (10 iterations)
 14→ *   4. Error tool_result on upstream MCP failure
 15→ *   5. Tool not injected without grant
 16→ *   6. Governance policy blocks execution
 17→ *   7. Connection reuse within request (multiple tools, same server)
 18→ *
 19→ * Driving ports:
 20→ *   POST /proxy/llm/anthropic/v1/messages  (proxy entry point)
 21→ */
 22→import { afterAll, beforeAll, describe, expect, it } from "bun:test";
 23→import {
 24→  setupToolRegistrySuite,
 25→  createTestUserWithMcp,
 26→  createMockMcpClientFactory,
 27→  createMockAnthropicMsw,
 28→  sendProxyRequest,
 29→  seedMcpServer,
 30→  seedDiscoveredTool,
 31→  seedGrant,
 32→  seedPolicy,
 33→  seedGovernance,
 34→  type MockToolUseBlock,
 35→} from "./tool-registry-ui-test-kit";
 36→
 37→// Mock MCP server that returns success for all tool calls
 38→const mockMcpFactory = createMockMcpClientFactory({
 39→  tools: [
 40→    {
 41→      name: "github.create_issue",
 42→      description: "Create a GitHub issue",
 43→      inputSchema: { type: "object", properties: { title: { type: "string" } } },
 44→    },
 45→    {
 46→      name: "github.list_issues",
 47→      description: "List GitHub issues",
 48→      inputSchema: { type: "object", properties: {} },
 49→      annotations: { readOnlyHint: true },
 50→    },
 51→    {
 52→      name: "github.create_comment",
 53→      description: "Create a comment on an issue",
 54→      inputSchema: { type: "object", properties: { body: { type: "string" } } },
 55→    },
 56→  ],
 57→  onCallTool: (name, args) => ({
 58→    content: [{ type: "text", text: JSON.stringify({ tool: name, status: "ok", args }) }],
 59→  }),
 60→});
 61→
 62→const getRuntime = setupToolRegistrySuite("tool_registry_ui_tool_execution", {
 63→  mcpClientFactory: mockMcpFactory,
 64→});
 65→
 66→// MSW mock for Anthropic API — configured per test via reset()
 67→const toolUseBlock = (name: string, input: Record<string, unknown>): MockToolUseBlock => ({
 68→  type: "tool_use",
 69→  id: `toolu_${crypto.randomUUID().slice(0, 8)}`,
 70→  name,
 71→  input,
 72→});
 73→
 74→const mockAnthropic = createMockAnthropicMsw([]);
 75→
 76→beforeAll(() => mockAnthropic.listen());
 77→afterAll(() => mockAnthropic.close());
 78→
 79→// ---------------------------------------------------------------------------
 80→// Happy Path: Single Tool Execution
 81→// ---------------------------------------------------------------------------
 82→describe("Proxy executes integration tool calls on upstream MCP server", () => {
 83→  it("executes a single integration tool call and returns final text", async () => {
 84→    const { baseUrl, surreal } = getRuntime();
 85→    const agent = await createTestUserWithMcp(baseUrl, surreal, `ws-exec-${crypto.randomUUID()}`);
 86→
 87→    const { serverId } = await seedMcpServer(surreal, agent.workspaceId, {
 88→      name: "GitHub Tools",
 89→      url: "https://mcp.test.local/github",
 90→      lastStatus: "ok",
 91→    });
 92→    const { toolId } = await seedDiscoveredTool(surreal, agent.workspaceId, serverId, {
 93→      name: "github.create_issue",
 94→      toolkit: "github",
 95→      description: "Create a GitHub issue",
 96→      inputSchema: { type: "object", properties: { title: { type: "string" } } },
 97→    });
 98→    await seedGrant(surreal, agent.identityId, toolId);
 99→
100→    // Mock: first call returns tool_use, second returns text
101→    mockAnthropic.reset([
102→      {
103→        content: [toolUseBlock("github.create_issue", { title: "Test issue" })],
104→        stopReason: "tool_use",
105→      },
106→      {
107→        content: [{ type: "text", text: "I created the issue for you." }],
108→        stopReason: "end_turn",
109→      },
110→    ]);
111→
112→    const res = await sendProxyRequest(baseUrl, surreal, agent, {
113→      messages: [{ role: "user", content: "Create a test issue" }],
114→    });
115→
116→    expect(res.status).toBe(200);
117→    const body = await res.json() as { content: Array<{ type: string; text?: string }> };
118→    // The final response should be the text response after tool execution
119→    const textBlock = body.content?.find((c) => c.type === "text");
120→    expect(textBlock?.text).toContain("created the issue");
121→    // Anthropic was called twice (initial + follow-up with tool_result)
122→    expect(mockAnthropic.callCount).toBe(2);
123→  }, 120_000);
124→});
125→
126→// ---------------------------------------------------------------------------
127→// Multi-Turn Loop
128→// ---------------------------------------------------------------------------
129→describe("Proxy handles multi-turn tool use loops", () => {
130→  it("completes multi-turn loop: tool call -> result -> tool call -> result -> text", async () => {
131→    const { baseUrl, surreal } = getRuntime();
132→    const agent = await createTestUserWithMcp(baseUrl, surreal, `ws-multi-${crypto.randomUUID()}`);
133→
134→    const { serverId } = await seedMcpServer(surreal, agent.workspaceId, {
