 37→export type SeedToolOptions = {
 38→  name: string;
 39→  toolkit: string;
 40→  description: string;
 41→  inputSchema: Record<string, unknown>;
 42→  outputSchema?: Record<string, unknown>;
 43→  provider?: string; // credential_provider record ID
 44→  riskLevel?: "low" | "medium" | "high" | "critical";
 45→  status?: "active" | "disabled";
 46→  workspaceId: string;
 47→};
