 49→/**
 50→ * Seed an mcp_tool record directly in SurrealDB.
 51→ * Returns the tool record ID string.
 52→ */
 53→export async function seedMcpTool(
 54→  surreal: Surreal,
 55→  toolId: string,
 56→  options: SeedToolOptions,
 57→): Promise<string> {
 58→  const toolRecord = new RecordId("mcp_tool", toolId);
 59→  const workspaceRecord = new RecordId("workspace", options.workspaceId);
 60→
 61→  const content: Record<string, unknown> = {
 62→    name: options.name,
 63→    toolkit: options.toolkit,
 64→    description: options.description,
 65→    input_schema: options.inputSchema,
 66→    risk_level: options.riskLevel ?? "medium",
 67→    workspace: workspaceRecord,
 68→    status: options.status ?? "active",
 69→    created_at: new Date(),
 70→  };
 71→
 72→  if (options.outputSchema) {
 73→    content.output_schema = options.outputSchema;
 74→  }
 75→
 76→  if (options.provider) {
 77→    content.provider = new RecordId("credential_provider", options.provider);
 78→  }
 79→
 80→  await surreal.query(`CREATE $tool CONTENT $content;`, {
 81→    tool: toolRecord,
 82→    content,
 83→  });
 84→
 85→  return toolId;
 86→}
