135→/**
136→ * Create a can_use relation edge from identity to mcp_tool.
137→ */
138→export async function seedCanUseEdge(
139→  surreal: Surreal,
140→  identityId: string,
141→  toolId: string,
142→  options?: { maxCallsPerHour?: number },
143→): Promise<void> {
144→  const identityRecord = new RecordId("identity", identityId);
145→  const toolRecord = new RecordId("mcp_tool", toolId);
146→
147→  const setClause = options?.maxCallsPerHour
148→    ? `SET granted_at = time::now(), max_calls_per_hour = ${options.maxCallsPerHour}`
149→    : `SET granted_at = time::now()`;
150→
151→  await surreal.query(
152→    `RELATE $identity->can_use->$tool ${setClause};`,
153→    { identity: identityRecord, tool: toolRecord },
154→  );
155→}
