278→
279→  const setClauses: string[] = [];
280→  if (options?.conditions) setClauses.push(`conditions = $conditions`);
281→  if (options?.maxPerCall !== undefined) setClauses.push(`max_per_call = ${options.maxPerCall}`);
282→  if (options?.maxPerDay !== undefined) setClauses.push(`max_per_day = ${options.maxPerDay}`);
