284→  const setString = setClauses.length > 0 ? `SET ${setClauses.join(", ")}` : "";
285→
286→  await surreal.query(
287→    `RELATE $policy->governs_tool->$tool ${setString};`,
288→    { policy: policyRecord, tool: toolRecord, conditions: options?.conditions },
289→  );
290→}
