488→/**
489→ * Send a request through the LLM proxy with identity headers for tool injection.
490→ * This is the driving port for tool injection tests (step 7.5) and
491→ * tool interception tests (step 8.5).
492→ */
493→export async function sendProxyRequestWithIdentity(
494→  baseUrl: string,
495→  options: {
496→    messages: Array<{ role: string; content: string }>;
497→    tools?: Array<{ name: string; description: string; input_schema: Record<string, unknown> }>;
498→    model?: string;
499→    maxTokens?: number;
500→    stream?: boolean;
501→    apiKey?: string;
502→    workspaceHeader?: string;
503→    identityHeader?: string;
504→  },
505→): Promise<Response> {
506→  const body = JSON.stringify({
507→    model: options.model ?? "claude-haiku-4-5-20251001",
508→    max_tokens: options.maxTokens ?? 100,
509→    stream: options.stream ?? false,
510→    messages: options.messages,
511→    ...(options.tools ? { tools: options.tools } : {}),
512→  });
513→
514→  const headers: Record<string, string> = {
515→    "Content-Type": "application/json",
516→    "anthropic-version": "2023-06-01",
517→  };
518→
519→  if (options.apiKey) headers["x-api-key"] = options.apiKey;
520→  if (options.workspaceHeader) headers["X-Brain-Workspace"] = options.workspaceHeader;
521→  if (options.identityHeader) headers["X-Brain-Identity"] = options.identityHeader;
522→
523→  return fetch(`${baseUrl}/proxy/llm/anthropic/v1/messages`, {
524→    method: "POST",
525→    headers,
526→    body,
527→  });
528→}
