  73→// ---------------------------------------------------------------------------
  74→// Mock MCP Client Factory
  75→// ---------------------------------------------------------------------------
  76→
  77→/** Configurable tool for mock MCP server. */
  78→export type MockMcpTool = {
  79→  name: string;
  80→  description: string;
  81→  inputSchema: Record<string, unknown>;
  82→  outputSchema?: Record<string, unknown>;
  83→  annotations?: Record<string, unknown>;
  84→};
  85→
  86→/** Configurable tool call handler. */
  87→export type MockToolCallHandler = (
  88→  name: string,
  89→  args: Record<string, unknown>,
  90→) => CallToolResult;
  91→
  92→/**
  93→ * Create a mock McpClientFactory that simulates upstream MCP servers.
  94→ *
  95→ * The mock returns configured tools from listTools and dispatches callTool
  96→ * to the provided handler (or returns a default success response).
  97→ */
  98→export function createMockMcpClientFactory(config: {
  99→  tools: MockMcpTool[];
 100→  onCallTool?: MockToolCallHandler;
 101→  serverInfo?: { name: string; version: string };
 102→}): McpClientFactory {
 103→  const defaultHandler: MockToolCallHandler = (name, args) => ({
 104→    content: [{ type: "text" as const, text: JSON.stringify({ tool: name, result: "success", args }) }],
 105→  });
 106→
 107→  const handler = config.onCallTool ?? defaultHandler;
 108→  const serverInfo = config.serverInfo ?? { name: "mock-mcp-server", version: "1.0.0" };
 109→
 110→  // Track connections for disconnect verification
 111→  const activeConnections = new Set<object>();
 112→
 113→  return {
 114→    connect: async (_url, _transport, _headers) => {
 115→      const fakeClient = {} as Client;
 116→      activeConnections.add(fakeClient);
 117→      return {
 118→        client: fakeClient,
 119→        serverInfo,
 120→        capabilities: { tools: { listChanged: true } },
 121→      } as McpConnectionResult;
 122→    },
 123→
 124→    fetchToolList: async (_client) => {
 125→      return {
 126→        tools: config.tools.map((t) => ({
 127→          name: t.name,
 128→          description: t.description,
 129→          inputSchema: t.inputSchema,
 130→          outputSchema: t.outputSchema,
 131→          annotations: t.annotations,
 132→        })),
 133→      } as ToolListResult;
 134→    },
 135→
 136→    callTool: async (_client, name, args) => {
 137→      return handler(name, args);
 138→    },
 139→
 140→    disconnect: async (client) => {
 141→      activeConnections.delete(client as object);
 142→    },
 143→  };
 144→}
