 401→/**
 402→ * Seed an mcp_tool record directly in SurrealDB for test preconditions.
 403→ */
 404→export async function seedTool(
 405→  surreal: Surreal,
 406→  workspaceId: string,
 407→  options: {
 408→    name: string;
 409→    toolkit: string;
 410→    description?: string;
 411→    riskLevel?: "low" | "medium" | "high" | "critical";
 412→    status?: "active" | "disabled";
 413→    providerId?: string;
 414→    inputSchema?: Record<string, unknown>;
 415→  },
 416→): Promise<{ toolId: string }> {
 417→  const toolId = `tool-${crypto.randomUUID()}`;
 418→  const toolRecord = new RecordId("mcp_tool", toolId);
 419→  const workspaceRecord = new RecordId("workspace", workspaceId);
 420→
 421→  const content: Record<string, unknown> = {
 422→    name: options.name,
 423→    toolkit: options.toolkit,
 424→    description: options.description ?? `${options.name} tool`,
 425→    input_schema: options.inputSchema ?? { type: "object", properties: {} },
 426→    risk_level: options.riskLevel ?? "medium",
 427→    workspace: workspaceRecord,
 428→    status: options.status ?? "active",
 429→    created_at: new Date(),
 430→  };
 431→
 432→  if (options.providerId) {
 433→    content.provider = new RecordId("credential_provider", options.providerId);
 434→  }
 435→
 436→  await surreal.query(`CREATE $tool CONTENT $content;`, {
 437→    tool: toolRecord,
 438→    content,
 439→  });
 440→
 441→  return { toolId };
 442→}
