 860→/**
 861→ * Create a proxy_token record in SurrealDB and return the raw token string.
 862→ * The proxy uses X-Brain-Auth: <raw-token> for identity resolution.
 863→ */
 864→export async function seedProxyToken(
 865→  surreal: Surreal,
 866→  identityId: string,
 867→  workspaceId: string,
 868→): Promise<string> {
 869→  const rawToken = `brn_test_${crypto.randomUUID()}`;
 870→  const tokenHash = createHash("sha256").update(rawToken).digest("hex");
 871→  const tokenId = `pt-${crypto.randomUUID()}`;
 872→  const tokenRecord = new RecordId("proxy_token", tokenId);
 873→
 874→  await surreal.query(`CREATE $rec CONTENT $content;`, {
 875→    rec: tokenRecord,
 876→    content: {
 877→      token_hash: tokenHash,
 878→      workspace: new RecordId("workspace", workspaceId),
 879→      identity: new RecordId("identity", identityId),
 880→      expires_at: new Date(Date.now() + 24 * 60 * 60 * 1000), // 24h
 881→      revoked: false,
 882→      created_at: new Date(),
 883→    },
 884→  });
 885→
 886→  return rawToken;
 887→}
