 893→/**
 894→ * Send a proxy request to the Anthropic Messages endpoint.
 895→ * Creates a proxy token on first call per user (cached on the user object).
 896→ */
 897→export async function sendProxyRequest(
 898→  baseUrl: string,
 899→  surreal: Surreal,
 900→  user: TestUserWithMcp,
 901→  options: {
 902→    messages: Array<{ role: string; content: string }>;
 903→    tools?: Array<{ name: string; description: string; input_schema: Record<string, unknown> }>;
 904→    model?: string;
 905→    maxTokens?: number;
 906→  },
 907→): Promise<Response> {
 908→  // Cache proxy token on user object to avoid re-creating per call
 909→  const cached = (user as unknown as { _proxyToken?: string })._proxyToken;
 910→  const proxyToken = cached ?? await seedProxyToken(surreal, user.identityId, user.workspaceId);
 911→  if (!cached) {
 912→    (user as unknown as { _proxyToken?: string })._proxyToken = proxyToken;
 913→  }
 914→
 915→  return fetch(`${baseUrl}/proxy/llm/anthropic/v1/messages`, {
 916→    method: "POST",
 917→    headers: {
 918→      "Content-Type": "application/json",
 919→      "anthropic-version": "2023-06-01",
 920→      "x-api-key": "test-api-key",
 921→      "X-Brain-Auth": proxyToken,
 922→    },
 923→    body: JSON.stringify({
 924→      model: options.model ?? "claude-haiku-4-5-20251001",
 925→      max_tokens: options.maxTokens ?? 100,
 926→      stream: false,
 927→      messages: options.messages,
 928→      ...(options.tools ? { tools: options.tools } : {}),
 929→    }),
 930→  });
 931→}
