 970→/**
 971→ * Create an MSW server that intercepts Anthropic Messages API calls.
 972→ *
 973→ * Returns a sequence of responses: each proxy request consumes the next
 974→ * response in the queue. After the queue is exhausted, returns a final
 975→ * text response.
 976→ *
 977→ * @param responses - Ordered list of Anthropic API responses to return
 978→ * @param anthropicApiUrl - Base URL of the Anthropic API (default: https://api.anthropic.com)
 979→ */
 980→export function createMockAnthropicMsw(
 981→  responses: Array<{ content: Array<MockToolUseBlock | MockTextBlock>; stopReason: "end_turn" | "tool_use" }>,
 982→  anthropicApiUrl = "https://api.anthropic.com",
 983→) {
 984→  let callIndex = 0;
 985→
 986→  const server = setupMswServer(
 987→    http.post(`${anthropicApiUrl}/v1/messages`, () => {
 988→      const idx = callIndex++;
 989→      if (idx < responses.length) {
 990→        return HttpResponse.json(
 991→          buildAnthropicResponse(responses[idx].content, responses[idx].stopReason),
 992→        );
 993→      }
 994→      // Default final response after queue exhausted
 995→      return HttpResponse.json(
 996→        buildAnthropicResponse(
 997→          [{ type: "text", text: "Done processing tool results." }],
 998→          "end_turn",
 999→        ),
1000→      );
1001→    }),
1002→  );
1003→
1004→  return {
1005→    server,
1006→    /** Number of times the Anthropic API was called. */
1007→    get callCount() { return callIndex; },
1008→    /** Start intercepting. Call in beforeAll or at test start. */
1009→    listen: () => server.listen({ onUnhandledRequest: "bypass" }),
1010→    /** Stop intercepting and clean up. Call in afterAll or at test end. */
1011→    close: () => { server.close(); callIndex = 0; },
1012→    /** Reset call count and response queue index. */
1013→    reset: (newResponses?: typeof responses) => {
1014→      callIndex = 0;
1015→      if (newResponses) {
1016→        responses = newResponses;
1017→      }
1018→    },
1019→  };
1020→}
