190→/**
191→ * Create a LookupProxyToken adapter backed by SurrealDB.
192→ * Queries the proxy_token table for a non-revoked, non-expired record
193→ * matching the given token hash.
194→ */
195→export function createLookupProxyToken(
196→  surreal: ServerDependencies["surreal"],
197→): LookupProxyToken {
198→  return async (tokenHash: string): Promise<ProxyTokenRecord | undefined> => {
199→    const results = await surreal.query<[ProxyTokenRow[]]>(
200→      `SELECT workspace, identity, expires_at, revoked FROM proxy_token WHERE token_hash = $hash LIMIT 1;`,
201→      { hash: tokenHash },
202→    );
203→
204→    const row = results[0]?.[0];
205→    if (!row) return undefined;
206→
207→    return {
208→      workspaceId: row.workspace.id as string,
209→      identityId: row.identity.id as string,
210→      expiresAt: new Date(row.expires_at),
211→      revoked: row.revoked,
212→    };
213→  };
214→}
