197→
198→export function createAccountRouteHandlers(deps: ServerDependencies) {
199→  const encryptionKey = deps.config.toolEncryptionKey;
200→
201→  /**
202→   * POST /api/workspaces/:workspaceId/accounts/connect/:providerId
203→   *
204→   * For api_key/bearer/basic: encrypts credentials and creates connected_account.
205→   * For oauth2: returns redirect URL for user to authorize at provider.
206→   */
207→  async function handleConnect(
208→    workspaceId: string,
209→    providerId: string,
210→    request: Request,
211→  ): Promise<Response> {
212→    let workspaceRecord;
213→    try {
214→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
215→    } catch (error) {
216→      if (error instanceof HttpError) {
217→        return jsonError(error.message, error.status);
218→      }
219→      log.error("account.connect", "Failed to resolve workspace", error, { workspaceId });
220→      return jsonError("internal error", 500);
221→    }
222→
223→    // Look up the credential provider
224→    const provider = await getProviderById(deps.surreal, providerId);
225→    if (!provider) {
226→      return jsonError("credential provider not found", 404);
227→    }
228→
229→    // Resolve identity from session (browser) or X-Brain-Identity header (MCP/CLI)
230→    const identityResult = await resolveIdentityFromSession(deps, request);
231→    if (identityResult instanceof Response) return identityResult;
232→
233→    const identityRecord = identityResult;
234→    const providerRecord = new RecordId("credential_provider", providerId);
235→
236→    // Check for existing active account
237→    const alreadyExists = await activeAccountExists(deps.surreal, identityRecord, providerRecord);
238→    if (alreadyExists) {
239→      return jsonError("active account already exists for this provider", 409);
240→    }
241→
242→    // OAuth2: return redirect URL
243→    if (provider.auth_method === "oauth2") {
244→      const state = crypto.randomUUID();
245→      const baseUrl = request.headers.get("Origin") ?? `${new URL(request.url).origin}`;
246→      const redirectUri = `${baseUrl}/api/workspaces/${workspaceId}/accounts/oauth2/callback`;
247→
248→      storeOAuthState(state, {
249→        providerId,
250→        identityId: identityRecord.id as string,
251→        workspaceId,
252→        createdAt: Date.now(),
253→      });
254→
255→      const redirectUrl = buildAuthorizationUrl(provider, redirectUri, state);
256→      return jsonResponse({ redirect_url: redirectUrl, state }, 200);
257→    }
258→
259→    // Static credentials: parse body and encrypt
260→    let body: ConnectAccountInput;
261→    try {
262→      body = await request.json() as ConnectAccountInput;
263→    } catch {
264→      return jsonError("invalid JSON body", 400);
265→    }
266→
267→    if (!encryptionKey) {
268→      log.error("account.connect", "TOOL_ENCRYPTION_KEY not configured", undefined, { workspaceId });
269→      return jsonError("encryption not configured", 500);
270→    }
271→
272→    const content: Record<string, unknown> = {
273→      identity: identityRecord,
274→      provider: providerRecord,
275→      workspace: workspaceRecord,
276→      status: "active",
277→    };
278→
279→    switch (provider.auth_method) {
280→      case "api_key": {
281→        if (!body.api_key) {
282→          return jsonError("api_key is required for api_key auth method", 400);
283→        }
284→        content.api_key_encrypted = encryptSecret(body.api_key, encryptionKey);
285→        break;
286→      }
287→      case "bearer": {
288→        if (!body.bearer_token) {
289→          return jsonError("bearer_token is required for bearer auth method", 400);
290→        }
291→        content.bearer_token_encrypted = encryptSecret(body.bearer_token, encryptionKey);
292→        break;
293→      }
294→      case "basic": {
295→        if (!body.basic_username || !body.basic_password) {
296→          return jsonError("basic_username and basic_password are required for basic auth method", 400);
297→        }
298→        content.basic_username = body.basic_username;
299→        content.basic_password_encrypted = encryptSecret(body.basic_password, encryptionKey);
300→        break;
301→      }
302→      default:
303→        return jsonError(`unsupported auth method: ${provider.auth_method}`, 400);
304→    }
305→
306→    const record = await createConnectedAccount(deps.surreal, content);
307→    return jsonResponse(toAccountApiResponse(record), 201);
308→  }
