327→      return jsonError("internal error", 500);
328→    }
329→
330→    const identityResult = await resolveIdentityFromSession(deps, request);
331→    if (identityResult instanceof Response) return identityResult;
332→
333→    const identityRecord = identityResult;
334→    const records = await listConnectedAccounts(deps.surreal, identityRecord, workspaceRecord);
335→    const accounts = records.map(toAccountApiResponse);
