341→   *
342→   * Revoke a connected account: sets status to "revoked" and hard-deletes
343→   * all encrypted credential fields. Idempotent.
344→   */
345→  async function handleRevoke(
346→    workspaceId: string,
347→    accountId: string,
348→    request: Request,
349→  ): Promise<Response> {
350→    let workspaceRecord;
351→    try {
352→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
353→    } catch (error) {
354→      if (error instanceof HttpError) {
355→        return jsonError(error.message, error.status);
356→      }
357→      log.error("account.revoke", "Failed to resolve workspace", error, { workspaceId });
358→      return jsonError("internal error", 500);
359→    }
360→
361→    const identityResult = await resolveIdentityFromSession(deps, request);
362→    if (identityResult instanceof Response) return identityResult;
363→
364→    const identityRecord = identityResult;
365→    const accountRecord = new RecordId("connected_account", accountId);
