 37→describe("Generate authorization URL with PKCE S256", () => {
 38→  it("returns authorization URL with code_challenge and state", async () => {
 39→    const { baseUrl, surreal } = getRuntime();
 40→    const user = await createTestUserWithMcp(baseUrl, surreal, `ws-auth-${crypto.randomUUID()}`);
 41→
 42→    // Given: MCP server registered
 43→    const mcpServerUrl = "https://mcp.example.com";
 44→    const authServerUrl = "https://auth.example.com";
 45→    const { msw } = setupMockMcpServer({ mcpServerUrl, authServerUrl, supportsDynamicRegistration: true });
 46→    msw.listen({ onUnhandledRequest: "bypass" });
 47→
 48→    try {
 49→      // Register an MCP server
 50→      const createRes = await user.mcpFetch(
 51→        `/api/workspaces/${user.workspaceId}/mcp-servers`,
 52→        { body: { name: "test-oauth-server", url: mcpServerUrl } },
 53→      );
 54→      expect(createRes.status).toBe(201);
 55→      const { id: serverId } = (await createRes.json()) as { id: string };
 56→
 57→      // Discover OAuth config (creates credential_provider linked to server)
 58→      const discoverRes = await user.mcpFetch(
 59→        `/api/workspaces/${user.workspaceId}/mcp-servers/${serverId}/discover-auth`,
 60→        { body: {} },
 61→      );
 62→      expect(discoverRes.status).toBe(200);
 63→      const discoverBody = (await discoverRes.json()) as {
 64→        discovered: boolean;
 65→        authorization_endpoint?: string;
 66→        scopes_supported?: string[];
 67→      };
 68→      expect(discoverBody.discovered).toBe(true);
 69→
 70→      // When: Initiate authorization
 71→      const authorizeRes = await user.mcpFetch(
 72→        `/api/workspaces/${user.workspaceId}/mcp-servers/${serverId}/authorize`,
 73→        { body: {} },
 74→      );
 75→      expect(authorizeRes.status).toBe(200);
 76→      const authorizeBody = (await authorizeRes.json()) as {
 77→        redirect_url: string;
 78→        state: string;
 79→      };
 80→
 81→      // Then: Response includes redirect_url and state
 82→      expect(authorizeBody.state).toBeDefined();
 83→      expect(typeof authorizeBody.state).toBe("string");
 84→      expect(authorizeBody.state.length).toBeGreaterThan(0);
 85→
 86→      expect(authorizeBody.redirect_url).toBeDefined();
 87→      const redirectUrl = new URL(authorizeBody.redirect_url);
 88→
 89→      // redirect_url points to the authorization_endpoint
 90→      expect(redirectUrl.origin + redirectUrl.pathname).toBe(`${authServerUrl}/authorize`);
 91→
 92→      // Contains code_challenge_method=S256
 93→      expect(redirectUrl.searchParams.get("code_challenge_method")).toBe("S256");
 94→
 95→      // Contains a code_challenge (base64url, no padding)
 96→      const codeChallenge = redirectUrl.searchParams.get("code_challenge");
 97→      expect(codeChallenge).toBeDefined();
 98→      expect(codeChallenge!.length).toBeGreaterThan(0);
 99→      // Base64url: only [A-Za-z0-9_-], no padding =
100→      expect(codeChallenge).toMatch(/^[A-Za-z0-9_-]+$/);
101→
102→      // Contains state matching the response body
103→      expect(redirectUrl.searchParams.get("state")).toBe(authorizeBody.state);
104→
105→      // Contains resource parameter (RFC 8707) matching the MCP server URI
106→      expect(redirectUrl.searchParams.get("resource")).toBe(mcpServerUrl);
107→
108→      // Contains scope parameter
109→      const scope = redirectUrl.searchParams.get("scope");
110→      expect(scope).toBeDefined();
111→      expect(scope!.length).toBeGreaterThan(0);
112→
113→      // Contains response_type=code
114→      expect(redirectUrl.searchParams.get("response_type")).toBe("code");
115→    } finally {
116→      msw.close();
117→    }
118→  }, 30_000);
119→});
