149→describe("Static headers injected on MCP connect", () => {
150→  it("MCP client sends configured headers when connecting to server", async () => {
151→    const { baseUrl, surreal } = getRuntime();
152→    const user = await createTestUserWithMcp(baseUrl, surreal, `ws-inject-${crypto.randomUUID()}`);
153→
154→    const mockUrl = "https://mcp-static-auth.example.com";
155→    const expectedAuth = "Bearer ghp_test_inject_123";
156→    const capturedRequests: CapturedRequest[] = [];
157→
158→    // Set up MSW mock that handles the full MCP JSON-RPC protocol
159→    // and requires the Authorization header on every request
160→    const msw = setupMswServer(
161→      http.post(mockUrl, async ({ request }) => {
162→        capturedRequests.push({
163→          url: request.url,
164→          method: request.method,
165→          headers: Object.fromEntries(request.headers.entries()),
166→        });
167→
168→        // Reject requests without the correct Authorization header
169→        const authHeader = request.headers.get("authorization");
170→        if (authHeader !== expectedAuth) {
171→          return new HttpResponse(null, { status: 401 });
172→        }
173→
174→        // Parse JSON-RPC request to dispatch by method
175→        const body = await request.json() as { jsonrpc: string; id?: number; method: string };
176→
177→        if (body.method === "initialize") {
178→          return HttpResponse.json({
179→            jsonrpc: "2.0",
180→            id: body.id,
181→            result: {
182→              protocolVersion: "2025-03-26",
183→              capabilities: { tools: {} },
184→              serverInfo: { name: "mock-mcp-server", version: "1.0.0" },
185→            },
186→          });
187→        }
188→
189→        if (body.method === "notifications/initialized") {
190→          // Notification -- no response needed but return 200
191→          return new HttpResponse(null, { status: 200 });
192→        }
193→
194→        if (body.method === "tools/list") {
195→          return HttpResponse.json({
196→            jsonrpc: "2.0",
197→            id: body.id,
198→            result: {
199→              tools: [
200→                {
201→                  name: "mock_tool",
202→                  description: "A mock tool for testing",
203→                  inputSchema: { type: "object", properties: {} },
204→                },
205→              ],
206→            },
207→          });
208→        }
209→
210→        // Unknown method
211→        return HttpResponse.json({
212→          jsonrpc: "2.0",
213→          id: body.id,
214→          error: { code: -32601, message: "Method not found" },
215→        });
216→      }),
217→    );
218→    msw.listen({ onUnhandledRequest: "bypass" });
219→
220→    try {
221→      // Given an MCP server with static header "Authorization: Bearer ghp_test_inject_123"
222→      const createResponse = await user.mcpFetch(
223→        `/api/workspaces/${user.workspaceId}/mcp-servers`,
224→        {
225→          method: "POST",
226→          body: {
227→            name: `inject-test-${crypto.randomUUID().slice(0, 8)}`,
228→            url: mockUrl,
229→            transport: "streamable-http",
230→            auth_mode: "static_headers",
231→            static_headers: [
232→              { name: "Authorization", value: expectedAuth },
233→            ],
234→          },
235→        },
236→      );
237→
238→      expect(createResponse.status).toBe(201);
239→      const { id: serverId } = await createResponse.json() as { id: string };
240→
241→      // When Brain connects to the MCP server for discovery
242→      const discoverResponse = await user.mcpFetch(
243→        `/api/workspaces/${user.workspaceId}/mcp-servers/${serverId}/discover`,
244→        { method: "POST" },
245→      );
246→
247→      // Then the discovery succeeds (server received correct auth header)
248→      expect(discoverResponse.status).toBe(200);
249→      const discoverBody = await discoverResponse.json() as { tools: Array<{ name: string }> };
250→
251→      // And tools/list returns tools from the authenticated server
252→      expect(discoverBody.tools).toBeDefined();
253→      expect(discoverBody.tools.length).toBeGreaterThan(0);
254→      expect(discoverBody.tools[0].name).toBe("mock_tool");
255→
256→      // And the HTTP request included the correct Authorization header
257→      expect(capturedRequests.length).toBeGreaterThan(0);
258→      const mcpRequest = capturedRequests.find((r) => r.headers.authorization === expectedAuth);
259→      expect(mcpRequest).toBeDefined();
260→    } finally {
261→      msw.close();
262→    }
263→  }, 30_000);
264→});
