521→      const discoverBody = await discoverResponse.json() as { tools: Array<{ name: string }> };
522→      expect(discoverBody.tools).toBeDefined();
523→      expect(discoverBody.tools.length).toBeGreaterThan(0);
524→      expect(discoverBody.tools[0].name).toBe("multi_header_tool");
525→
526→      // And both headers were present in the captured HTTP requests
527→      expect(capturedRequests.length).toBeGreaterThan(0);
528→      const authenticatedRequest = capturedRequests.find(
529→        (r) =>
530→          r.headers.authorization === expectedAuth &&
531→          r.headers["x-custom-header"] === expectedCustom,
532→      );
533→      expect(authenticatedRequest).toBeDefined();
534→    } finally {
535→      msw.close();
536→    }
537→  }, 30_000);
