 80→describe("Discover auth from WWW-Authenticate header on 401", () => {
 81→  it("falls back to WWW-Authenticate when .well-known is not available", async () => {
 82→    const { baseUrl, surreal } = getRuntime();
 83→    const user = await createTestUserWithMcp(baseUrl, surreal, `ws-www-auth-${crypto.randomUUID()}`);
 84→
 85→    // Given MCP server does NOT serve /.well-known/oauth-protected-resource
 86→    // But returns 401 with WWW-Authenticate: Bearer resource_metadata="..."
 87→    // The resource_metadata URL in the header can be any URL (not necessarily the well-known path)
 88→    const mcpServerUrl = "https://mcp-no-wellknown.example.com";
 89→    const authServerUrl = "https://auth-wwwauth.example.com";
 90→    const wellKnownUrl = `${mcpServerUrl}/.well-known/oauth-protected-resource`;
 91→    const resourceMetadataUrl = `${mcpServerUrl}/oauth/resource-metadata`;
 92→
 93→    const msw = setupMswServer(
 94→      // Standard .well-known returns 404 (not available)
 95→      http.get(wellKnownUrl, () => {
 96→        return new HttpResponse(null, { status: 404 });
 97→      }),
 98→
 99→      // MCP server returns 401 with WWW-Authenticate header pointing to resource metadata
100→      http.post(mcpServerUrl, () => {
101→        return new HttpResponse(null, {
102→          status: 401,
103→          headers: {
104→            "WWW-Authenticate": `Bearer resource_metadata="${resourceMetadataUrl}"`,
105→          },
106→        });
107→      }),
108→
109→      // The resource_metadata URL (from WWW-Authenticate) returns Protected Resource Metadata
110→      http.get(resourceMetadataUrl, () => {
111→        return HttpResponse.json({
112→          resource: mcpServerUrl,
113→          authorization_servers: [authServerUrl],
114→          scopes_supported: ["tools:read"],
115→          bearer_methods_supported: ["header"],
116→        });
117→      }),
118→
119→      // Auth server metadata
120→      http.get(`${authServerUrl}/.well-known/oauth-authorization-server`, () => {
121→        return HttpResponse.json({
122→          issuer: authServerUrl,
123→          authorization_endpoint: `${authServerUrl}/authorize`,
124→          token_endpoint: `${authServerUrl}/token`,
125→          scopes_supported: ["tools:read"],
126→          response_types_supported: ["code"],
127→          code_challenge_methods_supported: ["S256"],
128→          grant_types_supported: ["authorization_code"],
129→        });
130→      }),
131→    );
132→    msw.listen({ onUnhandledRequest: "bypass" });
133→
134→    try {
135→      // And an MCP server record exists
136→      const createResponse = await user.mcpFetch(
137→        `/api/workspaces/${user.workspaceId}/mcp-servers`,
138→        {
139→          method: "POST",
140→          body: {
141→            name: "www-auth-test",
142→            url: mcpServerUrl,
143→            transport: "streamable-http",
144→            auth_mode: "none",
145→          },
146→        },
147→      );
148→      const { id: serverId } = await createResponse.json() as { id: string };
149→
150→      // When admin triggers OAuth discovery
151→      const discoverResponse = await user.mcpFetch(
152→        `/api/workspaces/${user.workspaceId}/mcp-servers/${serverId}/discover-auth`,
153→        { method: "POST" },
154→      );
155→
156→      // Then discovery succeeds with auth server details
