 66→/**
 67→ * Update a credential_provider with client registration fields from DCR.
 68→ */
 69→export async function updateProviderClientRegistration(
 70→  surreal: Surreal,
 71→  providerRecord: RecordId<"credential_provider", string>,
 72→  clientId: string,
 73→  clientSecretEncrypted?: string,
 74→  authServerUrl?: string,
 75→): Promise<void> {
 76→  const setParts = ["client_id = $clientId"];
 77→  const bindings: Record<string, unknown> = { provider: providerRecord, clientId };
 78→
 79→  if (clientSecretEncrypted) {
 80→    setParts.push("client_secret_encrypted = $secret");
 81→    bindings.secret = clientSecretEncrypted;
 82→  }
 83→  if (authServerUrl) {
 84→    setParts.push("auth_server_url = $authServerUrl");
 85→    bindings.authServerUrl = authServerUrl;
 86→  }
 87→
 88→  await surreal.query(
 89→    `UPDATE $provider SET ${setParts.join(", ")};`,
 90→    bindings,
 91→  );
 92→}
