188→/** Row shape for governs_tool relation edges. */
189→export type GovernsPolicyRow = {
190→  readonly conditions?: string;
191→  readonly max_per_call?: number;
192→  readonly max_per_day?: number;
193→  readonly policyTitle: string;
194→  readonly policyStatus: string;
