196→
197→/**
198→ * Fetch all active governance policies for a tool by name.
199→ *
200→ * Joins governs_tool edges with their policy records, returning only
201→ * policies with status "active". Each row carries the edge conditions
202→ * and limits plus the policy title for trace/error messages.
203→ */
204→export async function fetchGovernancePolicies(
205→  surreal: Surreal,
206→  toolName: string,
207→): Promise<GovernsPolicyRow[]> {
208→  const results = await surreal.query<[GovernsPolicyRow[]]>(
209→    `SELECT
210→       conditions,
211→       max_per_call,
212→       max_per_day,
213→       in.title AS policyTitle,
214→       in.status AS policyStatus
