251→// ---------------------------------------------------------------------------
252→// SSE Usage Extraction
253→// ---------------------------------------------------------------------------
254→
255→type StreamContext = {
256→  model?: string;
257→  inputTokens: number;
258→  outputTokens: number;
259→  cacheCreationTokens: number;
260→  cacheReadTokens: number;
261→  stopReason?: string;
262→};
263→
264→function extractSSEUsage(buffer: string, ctx: StreamContext): string {
265→  const lines = buffer.split("\n");
266→  const remainder = lines.pop() ?? "";
267→
268→  for (const line of lines) {
269→    if (!line.startsWith("data: ")) continue;
270→    const data = line.slice(6);
271→    if (data === "[DONE]") continue;
272→
273→    try {
274→      const event = JSON.parse(data);
275→
276→      if (event.type === "message_start" && event.message?.usage) {
277→        ctx.inputTokens = event.message.usage.input_tokens ?? 0;
278→        ctx.cacheCreationTokens = event.message.usage.cache_creation_input_tokens ?? 0;
279→        ctx.cacheReadTokens = event.message.usage.cache_read_input_tokens ?? 0;
280→        ctx.model = event.message.model ?? ctx.model;
281→      }
282→
283→      if (event.type === "message_delta") {
284→        if (event.usage?.output_tokens) {
285→          ctx.outputTokens = event.usage.output_tokens;
286→        }
287→        if (event.delta?.stop_reason) {
288→          ctx.stopReason = event.delta.stop_reason;
289→        }
290→      }
291→    } catch {
292→      // partial JSON or non-JSON data line — skip
293→    }
294→  }
295→
296→  return remainder;
297→}
