299→// ---------------------------------------------------------------------------
300→// Non-Streaming Usage Extraction
301→// ---------------------------------------------------------------------------
302→
303→type NonStreamingResponse = {
304→  model?: string;
305→  usage?: {
306→    input_tokens?: number;
307→    output_tokens?: number;
308→    cache_creation_input_tokens?: number;
309→    cache_read_input_tokens?: number;
310→  };
311→  stop_reason?: string;
312→};
313→
314→function extractNonStreamingUsage(
315→  responseBody: string,
316→  requestModel: string | undefined,
317→  latencyMs: number,
318→  identity: { workspaceId?: string; taskId?: string; identityId?: string },
319→  sessionId?: string,
320→  policyDecision?: PolicyDecisionLog,
321→  injectionResult?: InjectionResult,
322→): TraceData | undefined {
323→  try {
324→    const parsed = JSON.parse(responseBody) as NonStreamingResponse;
325→    if (!parsed.usage) return undefined;
326→
327→    const responseContent = extractResponseContent(responseBody);
328→
329→    return {
330→      model: parsed.model ?? requestModel ?? "unknown",
331→      inputTokens: parsed.usage.input_tokens ?? 0,
332→      outputTokens: parsed.usage.output_tokens ?? 0,
333→      cacheCreationTokens: parsed.usage.cache_creation_input_tokens ?? 0,
334→      cacheReadTokens: parsed.usage.cache_read_input_tokens ?? 0,
335→      stopReason: parsed.stop_reason,
336→      latencyMs,
337→      workspaceId: identity.workspaceId,
338→      identityId: identity.identityId,
339→      sessionId,
340→      taskId: identity.taskId,
341→      policyDecision,
342→      ...(injectionResult ? { intelligenceMetadata: buildIntelligenceMetadata(injectionResult) } : {}),
343→      ...(responseContent ? { responseContent } : {}),
344→    };
345→  } catch {
346→    return undefined;
347→  }
348→}
