350→// ---------------------------------------------------------------------------
351→// Context Candidate Pool Loader (adapter boundary)
352→// ---------------------------------------------------------------------------
353→
354→const DECISION_WEIGHT = 1.0;
355→const LEARNING_WEIGHT = 0.8;
356→const OBSERVATION_WEIGHT = 0.7;
357→
358→async function loadCandidatePool(
359→  surreal: ServerDependencies["surreal"],
360→  workspaceId: string,
361→): Promise<CachedCandidatePool> {
362→  const workspaceRecord = new RecordId("workspace", workspaceId);
363→
364→  type DecisionRow = { id: RecordId; summary: string };
365→  type LearningRow = { id: RecordId; text: string };
366→  type ObservationRow = { id: RecordId; text: string };
367→
368→  // Single round-trip: no embedding fields fetched (02-01)
369→  const results = await surreal.query<[DecisionRow[], LearningRow[], ObservationRow[]]>(
370→    `SELECT id, summary FROM decision WHERE workspace = $ws AND status = 'confirmed' LIMIT 50;
371→     SELECT id, text FROM learning WHERE workspace = $ws AND status = 'active' LIMIT 30;
372→     SELECT id, text FROM observation WHERE workspace = $ws AND status = 'open' AND severity IN ['conflict', 'warning'] AND source_agent != 'llm-proxy' LIMIT 20;`,
373→    { ws: workspaceRecord },
374→  );
375→
376→  function toCandidates<T extends { id: RecordId }>(
377→    rows: T[],
378→    type: CandidateItem["type"],
379→    weight: number,
380→    textFn: (row: T) => string,
381→  ): CandidateItem[] {
382→    return rows.map((row) => ({
383→      id: (row.id as RecordId).id as string,
384→      type,
385→      text: textFn(row),
386→      weight,
387→    }));
388→  }
389→
390→  const decisions = toCandidates(results[0] ?? [], "decision", DECISION_WEIGHT, (d) => d.summary);
391→  const learnings = toCandidates(results[1] ?? [], "learning", LEARNING_WEIGHT, (l) => l.text);
392→  const observations = toCandidates(results[2] ?? [], "observation", OBSERVATION_WEIGHT, (o) => o.text);
393→
394→  return {
395→    decisions,
396→    learnings,
397→    observations,
398→    populatedAt: Date.now(),
399→  };
400→}
401→
402→// ---------------------------------------------------------------------------
403→// Context Injection Pipeline (orchestrator)
404→// ---------------------------------------------------------------------------
405→
406→type ContextInjectionResult = {
407→  readonly body: string;
408→  readonly injectionResult?: InjectionResult;
409→};
410→
411→async function runContextInjection(
412→  deps: ServerDependencies,
413→  workspaceId: string,
414→  parsedBody: ParsedBody,
415→  originalBody: string,
416→  contextCache: ContextCache,
417→  intelligenceConfig: IntelligenceConfig,
418→  fetchRecentChanges?: FetchRecentChangesByTime,
419→  searchContextByBm25?: SearchContextByBm25,
420→): Promise<ContextInjectionResult> {
421→  if (!intelligenceConfig.contextInjectionEnabled) {
422→    return { body: originalBody };
423→  }
424→
425→  // 1. Extract last user message text (for BM25 query)
426→  const messages = parsedBody.messages ?? [];
427→  let lastUserMessage: { role: string; content: string } | undefined;
428→  for (let i = messages.length - 1; i >= 0; i--) {
429→    if (messages[i].role === "user") { lastUserMessage = messages[i]; break; }
430→  }
431→  if (!lastUserMessage) {
432→    return { body: originalBody };
433→  }
434→
435→  const queryText = lastUserMessage.content;
436→  const now = new Date();
437→
438→  // 2. Search context candidates via BM25 fulltext (no embeddings)
439→  let selectedCandidates;
440→  if (searchContextByBm25) {
441→    // BM25 path: query-time search ranked by relevance + recency
442→    const bm25Candidates = await searchContextByBm25(queryText, workspaceId, 100);
443→
444→    if (bm25Candidates.length === 0) {
445→      // Fallback: load cached pool without ranking (weight-based)
446→      const pool = await loadFallbackPool(deps, workspaceId, contextCache);
447→      if (!pool) return { body: originalBody };
448→      const allCandidates = [...pool.decisions, ...pool.learnings, ...pool.observations];
449→      const ranked = allCandidates.map((c) => ({ id: c.id, type: c.type, text: c.text, score: c.weight }));
450→      selectedCandidates = selectWithinBudget(ranked, intelligenceConfig.contextInjectionTokenBudget);
451→    } else {
452→      log.info("proxy.context_injection.bm25_search", "BM25 context search completed", {
453→        workspace_id: workspaceId,
454→        candidates: bm25Candidates.length,
455→      });
456→      const ranked = rankByBm25WithRecency(bm25Candidates, now);
457→      selectedCandidates = selectWithinBudget(ranked, intelligenceConfig.contextInjectionTokenBudget);
458→    }
459→  } else {
460→    // Legacy fallback: cached pool with weight-based ranking (no embeddings)
461→    const pool = await loadFallbackPool(deps, workspaceId, contextCache);
462→    if (!pool) return { body: originalBody };
463→    const allCandidates: ContextCandidate[] = [...pool.decisions, ...pool.learnings, ...pool.observations];
464→    const ranked = allCandidates.map((c) => ({ id: c.id, type: c.type, text: c.text, score: c.weight }));
465→    selectedCandidates = selectWithinBudget(ranked, intelligenceConfig.contextInjectionTokenBudget);
466→  }
467→
468→  if (selectedCandidates.length === 0) {
469→    return { body: originalBody };
470→  }
471→
472→  // 3. Build XML block
473→  const brainContextXml = buildBrainContextXml(selectedCandidates);
474→
475→  // 4. Inject into system prompt
476→  const injectionResult = injectBrainContext(parsedBody.system, brainContextXml);
477→
478→  // 5. Fetch and inject recent changes by time window (no embeddings, no BM25)
479→  let enrichedSystem = injectionResult.system;
480→  if (fetchRecentChanges) {
481→    try {
482→      const timeWindowMs = 24 * 60 * 60 * 1000; // 24-hour window
483→      const cutoff = buildTimeWindowCutoff(now, timeWindowMs);
484→      const recentCandidates = await fetchRecentChanges(workspaceId, cutoff, 20);
485→      const classified = classifyByAge(recentCandidates, now);
486→      const recentChangesXml = buildRecentChangesXml(classified);
487→      if (recentChangesXml) {
488→        enrichedSystem = injectRecentChanges(enrichedSystem, recentChangesXml);
489→      }
490→    } catch (error) {
491→      // Fail-open: log and continue without recent changes
492→      log.warn("proxy.context_injection.recent_changes_failed", "Recent changes fetch failed", {
493→        workspace_id: workspaceId,
494→        error: String(error),
495→      });
496→    }
497→  }
498→
499→  // 6. Build modified request body
500→  const modifiedBody = {
501→    ...parsedBody,
502→    system: enrichedSystem,
503→  };
504→
505→  return {
506→    body: JSON.stringify(modifiedBody),
507→    injectionResult,
508→  };
509→}
