511→/** Load fallback candidate pool from cache or DB (legacy path). */
512→async function loadFallbackPool(
513→  deps: ServerDependencies,
514→  workspaceId: string,
515→  contextCache: ContextCache,
516→): Promise<CachedCandidatePool | undefined> {
517→  let fromCache = false;
518→  const pool = contextCache.has(workspaceId)
519→    ? (fromCache = true, contextCache.get(workspaceId)!)
520→    : await loadCandidatePool(deps.surreal, workspaceId);
521→
522→  if (!fromCache) {
523→    contextCache.set(workspaceId, pool);
524→  }
525→
526→  const total = pool.decisions.length + pool.learnings.length + pool.observations.length;
527→  if (total === 0) return undefined;
528→
529→  log.info("proxy.context_injection.pool_loaded", "Candidate pool loaded", {
530→    workspace_id: workspaceId,
531→    decisions: pool.decisions.length,
532→    learnings: pool.learnings.length,
533→    observations: pool.observations.length,
534→    total,
535→    cached: fromCache,
536→  });
537→
538→  return pool;
539→}
