 72→/**
 73→ * Creates MSW handlers that simulate an MCP server with OAuth 2.1 support.
 74→ *
 75→ * - Protected Resource Metadata at /.well-known/oauth-protected-resource
 76→ * - Auth Server Metadata at /.well-known/oauth-authorization-server
 77→ * - Token endpoint at /token
 78→ * - Optional dynamic registration at /register
 79→ * - MCP endpoint that requires auth (returns 401 without, 200 with)
 80→ */
 81→export function createMockMcpHandlers(config: MockMcpServerConfig) {
 82→  const {
 83→    mcpServerUrl,
 84→    authServerUrl = "https://auth.example.com",
 85→    scopesSupported = ["read", "write"],
 86→    supportsDynamicRegistration = false,
 87→    expectedAuthHeader,
 88→    capturedRequests = [],
 89→  } = config;
 90→
 91→  return [
 92→    // Protected Resource Metadata (RFC 9728)
 93→    http.get(`${mcpServerUrl}/.well-known/oauth-protected-resource`, () => {
 94→      return HttpResponse.json({
 95→        resource: mcpServerUrl,
 96→        authorization_servers: [authServerUrl],
 97→        scopes_supported: scopesSupported,
 98→        bearer_methods_supported: ["header"],
 99→      });
100→    }),
101→
102→    // Auth Server Metadata (RFC 8414)
103→    http.get(`${authServerUrl}/.well-known/oauth-authorization-server`, () => {
104→      const metadata: Record<string, unknown> = {
105→        issuer: authServerUrl,
106→        authorization_endpoint: `${authServerUrl}/authorize`,
107→        token_endpoint: `${authServerUrl}/token`,
108→        scopes_supported: scopesSupported,
109→        response_types_supported: ["code"],
110→        code_challenge_methods_supported: ["S256"],
111→        grant_types_supported: ["authorization_code", "refresh_token"],
112→      };
113→
114→      if (supportsDynamicRegistration) {
115→        metadata.registration_endpoint = `${authServerUrl}/register`;
116→      }
117→
118→      return HttpResponse.json(metadata);
119→    }),
120→
121→    // Token endpoint — validates code + code_verifier, returns tokens
122→    http.post(`${authServerUrl}/token`, async ({ request }) => {
123→      const body = await request.text();
124→      const params = new URLSearchParams(body);
125→      const grantType = params.get("grant_type");
126→
127→      if (grantType === "authorization_code") {
128→        const code = params.get("code");
129→        const codeVerifier = params.get("code_verifier");
130→
131→        if (!code || !codeVerifier) {
132→          return HttpResponse.json(
133→            { error: "invalid_request", error_description: "Missing code or code_verifier" },
134→            { status: 400 },
135→          );
136→        }
137→
138→        return HttpResponse.json({
139→          access_token: `mock-access-token-${crypto.randomUUID().slice(0, 8)}`,
140→          token_type: "Bearer",
141→          expires_in: 3600,
142→          refresh_token: `mock-refresh-token-${crypto.randomUUID().slice(0, 8)}`,
143→          scope: scopesSupported.join(" "),
144→        });
145→      }
146→
147→      if (grantType === "refresh_token") {
148→        const refreshToken = params.get("refresh_token");
149→        if (!refreshToken) {
150→          return HttpResponse.json(
151→            { error: "invalid_grant", error_description: "Missing refresh_token" },
152→            { status: 400 },
153→          );
154→        }
155→
156→        return HttpResponse.json({
157→          access_token: `mock-refreshed-token-${crypto.randomUUID().slice(0, 8)}`,
158→          token_type: "Bearer",
159→          expires_in: 3600,
160→          refresh_token: `mock-refresh-token-${crypto.randomUUID().slice(0, 8)}`,
161→        });
162→      }
163→
164→      return HttpResponse.json(
165→        { error: "unsupported_grant_type" },
166→        { status: 400 },
167→      );
168→    }),
169→
170→    // Dynamic registration (RFC 7591)
171→    http.post(`${authServerUrl}/register`, async ({ request }) => {
172→      if (!supportsDynamicRegistration) {
173→        return new HttpResponse(null, { status: 404 });
174→      }
175→
176→      const body = await request.json() as Record<string, unknown>;
177→      return HttpResponse.json({
178→        client_id: `dynamic-client-${crypto.randomUUID().slice(0, 8)}`,
179→        client_secret: `dynamic-secret-${crypto.randomUUID().slice(0, 8)}`,
180→        client_name: body.client_name,
181→        redirect_uris: body.redirect_uris,
182→      });
183→    }),
184→
185→    // MCP server endpoint — requires auth, captures requests
186→    http.post(mcpServerUrl, ({ request }) => {
187→      capturedRequests.push({
188→        url: request.url,
189→        method: request.method,
190→        headers: Object.fromEntries(request.headers.entries()),
191→      });
192→
193→      const authHeader = request.headers.get("authorization");
194→
195→      if (expectedAuthHeader && authHeader !== expectedAuthHeader) {
196→        return new HttpResponse(null, {
197→          status: 401,
198→          headers: {
199→            "WWW-Authenticate": `Bearer resource_metadata="${mcpServerUrl}/.well-known/oauth-protected-resource"`,
200→          },

