645→export function createAnthropicProxyHandler(
646→  deps: ServerDependencies,
647→): (request: Request) => Promise<Response> {
648→  const workspaceCache: WorkspaceCache = new Map();
649→  const rateLimiterState: RateLimiterState = createRateLimiterState();
650→  const spendCache: SpendCache = new Map();
651→  const noPolicyWarnedWorkspaces = new Set<string>();
652→  const contextCache: ContextCache = createContextCache(300); // default TTL, overridden per-workspace
653→
654→  // Proxy auth: per-handler cache + DB lookup function (not module-level singletons)
655→  const proxyTokenCache: TokenCache = createTokenCache();
656→  const lookupProxyToken: LookupProxyToken = createLookupProxyToken(deps.surreal);
657→
658→  // Context search adapters (02-01: BM25 for context, 02-03: time-based for recent changes)
659→  const fetchRecentChanges: FetchRecentChangesByTime = createFetchRecentChangesByTime(deps.surreal);
660→  const searchContextByBm25: SearchContextByBm25 = createSearchContextByBm25(deps.surreal);
661→
662→  // Tool injection (02-01): per-instance cache + DB query adapter (not module-level singleton)
663→  const toolResolutionCache: ToolResolutionCache = createToolResolutionCache();
664→  const queryGrantedTools: QueryGrantedTools = createQueryGrantedTools(deps.surreal);
665→
666→  // Periodic pruning of stale rate limiter entries to prevent unbounded Map growth.
667→  // unref() ensures this interval does not keep the process alive on shutdown.
668→  const pruneInterval = setInterval(
669→    () => {
670→      pruneStaleEntries(rateLimiterState, Date.now());
671→      const nowMs = Date.now();
672→      for (const [key, entry] of proxyTokenCache) {
673→        if (nowMs >= entry.expiresAt) proxyTokenCache.delete(key);
674→      }
675→    },
676→    5 * 60 * 1000,
677→  );
678→  pruneInterval.unref();
679→
680→  const anthropicApiUrl = deps.config.anthropicApiUrl;
681→
682→  return async (request: Request): Promise<Response> => {
683→    const startedAt = performance.now();
684→    const url = new URL(request.url);
685→    const upstreamPath = url.pathname.replace(/^\/proxy\/llm\/anthropic/, "");
686→    const upstreamUrl = `${anthropicApiUrl}${upstreamPath}`;
687→    const isCountTokens = isCountTokensRequest(url.pathname);
688→    const span = trace.getActiveSpan();
689→    const traceId = span?.spanContext().traceId;
690→    const requestMode = request.headers.get("X-Brain-Auth") ? "brain" : "direct";
691→
692→    const setSpanAttributes = (attributes: Record<string, string | number | boolean | undefined>) => {
693→      if (!span) return;
694→      for (const [key, value] of Object.entries(attributes)) {
695→        if (value !== undefined) {
696→          span.setAttribute(key, value);
697→        }
698→      }
699→    };
700→
701→    let currentStage: ProxyStage = "parse_request";
702→    const setStage = (stage: ProxyStage) => {
703→      currentStage = stage;
704→      setSpanAttributes({ "proxy.stage": stage });
705→    };
706→    setStage("parse_request");
707→
708→    setSpanAttributes({
709→      "proxy.path": upstreamPath,
710→      "proxy.upstream_url": upstreamUrl,
711→      "proxy.is_count_tokens": isCountTokens,
712→      "proxy.request_mode": requestMode,
713→    });
714→
715→    // --- Step 1: Parse request body (malformed body forwarded as-is) ---
716→    let body: string;
717→    let parsed: ParsedBody | undefined;
718→    let isStreaming = false;
719→    let identitySignals:
720→      | ReturnType<typeof resolveIdentity>
721→      | undefined;
722→
723→    try {
724→      body = await request.text();
725→      parsed = tryParseRequestBody(body);
726→      isStreaming = parsed?.stream === true;
727→      setSpanAttributes({
728→        "proxy.request_body_parsed": parsed !== undefined,
729→        "proxy.request_body_bytes": body.length,
730→        "proxy.request_model": parsed?.model,
731→        "proxy.is_streaming": isStreaming,
732→      });
733→
734→      // --- Step 1.5: Brain auth resolution (dual-mode) ---
735→      setStage("resolve_auth");
736→      let brainAuthResult: ProxyAuthResult | undefined;
737→      let authMode: AuthMode = { mode: "direct" };
738→
739→      try {
740→        brainAuthResult = await resolveProxyAuth(
741→          request.headers,
742→          lookupProxyToken,
743→          proxyTokenCache,
744→        );
745→      } catch (error) {
746→        if (error instanceof ProxyAuthError) {
747→          setSpanAttributes({
748→            "proxy.error.type": "authentication_error",
749→            "proxy.error.stage": currentStage,
750→          });
751→          log.warn("proxy.anthropic.auth_failed", "Brain auth failed", {
752→            stage: currentStage,
753→            error: error.message,
754→          });
755→          return jsonResponse(
756→            buildProxyErrorPayload(
757→              "authentication_error",
758→              error.message,
759→              { stage: currentStage, traceId },
760→            ),
761→            401,
762→          );
763→        }
764→        throw error;
765→      }
766→
767→      if (brainAuthResult) {
768→        // Brain auth mode: use server API key if available, otherwise forward client auth headers
769→        authMode = { mode: "brain", serverApiKey: deps.config.anthropicApiKey };
770→      }
771→      setSpanAttributes({ "proxy.auth_mode": authMode.mode });
772→
773→      // --- Step 2: Identity resolution ---
774→      setStage("resolve_identity");
775→      // In Brain auth mode, workspace comes from the token (not from headers)
776→      identitySignals = resolveIdentity({
777→        metadataUserId: parsed?.metadata?.user_id,
778→        workspaceHeader: brainAuthResult?.workspaceId ?? (request.headers.get("X-Brain-Workspace") ?? undefined),
779→        taskHeader: request.headers.get("X-Brain-Task") ?? undefined,
780→        agentTypeHeader: request.headers.get("X-Brain-Agent-Type") ?? undefined,
781→        sessionHeader: request.headers.get("X-Brain-Session") ?? undefined,
782→        proxyTokenIdentityId: brainAuthResult?.identityId,
783→        userAgent: request.headers.get("User-Agent") ?? undefined,
784→      });
785→      setSpanAttributes({
786→        "proxy.workspace_id": identitySignals.workspaceId,
787→        "proxy.task_id": identitySignals.taskId,
788→        "proxy.agent_type": identitySignals.agentType,
789→        "proxy.session_header": identitySignals.sessionHeaderId,
790→      });
791→
792→      // --- Step 3: Session ID resolution ---
